+fn sanitize_ascii_header_value(value: &str, fallback: &str) -> String {
+    if value.is_ascii() && !value.trim().is_empty() {
+        return value.to_string();
+    }
+    let sanitized = value
+        .chars()
+        .filter(char::is_ascii)
+        .collect::<String>()
+        .trim()
+        .to_string();
+    if sanitized.is_empty() {
+        fallback.to_string()
+    } else {
+        sanitized
+    }
+}
